{
  "schemaVersion": 3,
  "arcId": "arc_1_khoi_nghiep_kim_bien",
  "startChapter": 1,
  "endChapter": 30,
  "direction": "An vươn lên từ thợ vá thuê bần cùng tại chợ Kim Biên, dùng kỹ thuật vô ảnh để thu hút sự chú ý của giới sưu tầm cao cấp, đồng thời chạm trán mạng lưới làm giả hồ sơ của Phạm Tôn.",
  "terminalChange": "An thanh toán dứt điểm khoản nợ giang hồ khẩn cấp, thoát khỏi sự chèn ép của Lão Cẩn, trở thành khách mời danh dự của Ông Lâm. Tuy nhiên, lượng men tro bí truyền cạn kiệt xuống mức báo động, và An phát hiện manh mối đầu tiên chứng minh Lò Rồng bị hãm hại.",
  "activeConflicts": [
    {
      "id": "conflict_can_boc_lot",
      "actorIds": [
        "char_an",
        "char_can"
      ],
      "objective": "Lão Cẩn muốn ép An vá đồ giả để lừa khách lấy tiền hoa hồng cao, trong khi An kiên quyết bảo vệ nguyên tắc không làm giả cổ vật.",
      "leverage": "Lão Cẩn nắm giữ nguồn hàng phế liệu mà An cần để tìm kiếm cổ vật thật, đồng thời biết rõ áp lực nợ nần của An.",
      "nextMove": "Lão Cẩn gài bẫy giao cho An một chiếc bình mộc mới tinh nhưng yêu cầu phủ men tro để giả làm đồ cổ thời Nguyễn."
    },
    {
      "id": "conflict_giam_dinh_ong_lam",
      "actorIds": [
        "char_an",
        "char_lam",
        "char_ton"
      ],
      "objective": "An muốn chứng minh bộ ấm chén ngự dụng là đồ giả mạo tinh vi, trong khi phe cánh của Phạm Tôn dùng hồ sơ giả để thuyết phục Ông Lâm mua với giá trên trời.",
      "leverage": "Phạm Tôn có giấy tờ chứng minh nguồn gốc hoàn hảo và uy tín học thuật. An chỉ có kính hiển vi cầm tay và kiến thức về tạp chất men công nghiệp.",
      "nextMove": "An sẽ can thiệp trực tiếp vào buổi giao dịch kín của Ông Lâm, đập vỡ một chiếc chén để soi cấu trúc xương gốm trước mặt mọi người."
    }
  ],
  "duePromiseIds": [
    "prom_tra_no"
  ],
  "progressionBudget": [
    {
      "signal": "Số lượng men tro còn lại",
      "requiredChange": "Giảm mạnh từ 100 gram xuống dưới 30 gram do phải thực hiện hai ca phục chế vô ảnh quy mô lớn để lấy tiền trả nợ, tạo áp lực phải tìm công thức mới."
    },
    {
      "signal": "Cấp độ của nhà sưu tầm tiếp cận được",
      "requiredChange": "Thăng cấp từ việc chỉ giao dịch với con buôn chợ trời (Lão Cẩn) sang việc được bước vào phòng trà VIP và thẩm định đồ cho nhà sưu tầm ẩn danh (Ông Lâm)."
    },
    {
      "signal": "Số trang nhật ký gia tộc thu thập được",
      "requiredChange": "Tìm thấy 3 trang nhật ký đầu tiên được giấu kín trong lớp đáy kép của một chiếc bát Lò Rồng vỡ, hé lộ sự tồn tại của kẻ phản bội."
    }
  ]
}
